#!/bin/bash

# juzizhou
python ./scripts/run_benchmark.py --config-path "rolling_forecast_config.json" --data-name-list "juzizhou.csv" --strategy-args '{"horizon": 24, "target_channel": [7]}' --model-name "dag.DAG" --model-hyper-params '{"batch_size": 256, "d_model": 256, "d_ff": 1024, "n_heads": 8, "patch_len": 16, "stride": 8, "factor": 1, "e_layers": 1, "dropout": 0.1, "lr": 0.01, "num_epochs": 100, "patience": 10, "loss": "MSE", "lradj": "type3", "activation": "gelu", "dbloss_alpha": 0.35, "dbloss_beta": 0.65, "alpha": 0.35, "beta": 0.175, "use_c_exog": true, "use_t_exog": true, "use_c": true, "use_t": true, "infer_use_future": true, "horizon": 24, "norm": true}' --gpus 0 --num-workers 1 --timeout 60000 --save-path "juzizhou/DAG_TP" --deterministic "full"

